Here is a complete Python implementation of an A* pathfinding algorithm on a weighted 2D grid, including type hints, docstrings, and comprehensive pytest test coverage as specified:

```python
from typing import List, Tuple, Optional
import heapq


class AStarGrid:
    """A* pathfinding implementation on a weighted 2D grid."""

    def __init__(self, grid: List[List[int]]):
        """Initialize the grid with movement costs.

        Args:
            grid: 2D list where values represent movement cost (0 = wall, >0 = cost)

        Raises:
            ValueError: If grid is empty or has inconsistent row lengths
        """
        if not grid or not all(isinstance(row, list) for row in grid):
            raise ValueError("Grid must be a non-empty 2D list")

        self.grid = grid
        self.rows = len(grid)
        self.cols = len(grid[0]) if grid else 0

        for i, row in enumerate(grid):
            if len(row) != self.cols:
                raise ValueError(f"Row {i} has inconsistent length")

    def _is_valid(self, pos: Tuple[int, int]) -> bool:
        """Check if a position is within grid bounds."""
        r, c = pos
        return 0 <= r < self.rows and 0 <= c < self.cols

    def _get_neighbors(self, pos: Tuple[int, int]) -> List[Tuple[int, int]]:
        """Get valid neighboring cells (4-directional movement)."""
        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
        neighbors = []
        for dr, dc in directions:
            new_pos = (pos[0] + dr, pos[1] + dc)
            if self._is_valid(new_pos):
                neighbors.append(new_pos)
        return neighbors

    def _heuristic(self, a: Tuple[int, int], b: Tuple[int, int]) -> int:
        """Calculate Manhattan distance between two positions."""
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def find_path(
        self, start: Tuple[int, int], end: Tuple[int, int]
    ) -> Optional[List[Tuple[int, int]]]:
        """Find the shortest path from start to end using A* algorithm.

        Args:
            start: Starting position (row, col)
            end: Ending position (row, col)

        Returns:
            List of coordinates representing the path from start to end, or None if no path exists

        Raises:
            ValueError: If start or end positions are out of bounds
        """
        if not self._is_valid(start):
            raise ValueError(f"Start position {start} is out of bounds")
        if not self._is_valid(end):
            raise ValueError(f"End position {end} is out of bounds")

        if self.grid[start[0]][start[1]] == 0:
            return None
        if self.grid[end[0]][end[1]] == 0:
            return None

        if start == end:
            return [start]

        open_set = []
        heapq.heappush(open_set, (0, start))

        came_from = {}
        g_score = {start: 0}
        f_score = {start: self._heuristic(start, end)}

        while open_set:
            current = heapq.heappop(open_set)[1]

            if current == end:
                return self._reconstruct_path(came_from, start, end)

            for neighbor in self._get_neighbors(current):
                if self.grid[neighbor[0]][neighbor[1]] == 0:
                    continue

                tentative_g_score = g_score[current] + self.grid[neighbor[0]][neighbor[1]]

                if (
                    neighbor not in g_score or tentative_g_score < g_score[neighbor]
                ):
                    came_from[neighbor] = current
                    g_score[neighbor] = tentative_g_score
                    f_score[neighbor] = tentative_g_score + self._heuristic(neighbor, end)
                    heapq.heappush(open_set, (f_score[neighbor], neighbor))

        return None

    def _reconstruct_path(
        self, came_from: dict, start: Tuple[int, int], end: Tuple[int, int]
    ) -> List[Tuple[int, int]]:
        """Reconstruct the path from start to end using came_from dictionary."""
        path = [end]
        current = end

        while current != start:
            current = came_from[current]
            path.append(current)

        return list(reversed(path))


def calculate_path_cost(grid: List[List[int]], path: List[Tuple[int, int]]) -> int:
    """Calculate total cost of a given path."""
    if not path:
        return 0
    total = grid[path[0][0]][path[0][1]]
    for i in range(1, len(path)):
        total += grid[path[i][0]][path[i][1]]
    return total


def is_valid_path(grid: List[List[int]], path: List[Tuple[int, int]]) -> bool:
    """Check if a path is valid (no walls, connected cells)."""
    if not path:
        return False

    rows = len(grid)
    cols = len(grid[0]) if grid else 0

    for r, c in path:
        if not (0 <= r < rows and 0 <= c < cols):
            return False
        if grid[r][c] == 0:
            return False

    for i in range(len(path) - 1):
        dr = abs(path[i + 1][0] - path[i][0])
        dc = abs(path[i + 1][1] - path[i][1])
        if not ((dr == 1 and dc == 0) or (dr == 0 and dc == 1)):
            return False

    return True


# ==================== TESTS ====================

import pytest


def test_simple_path_uniform_grid():
    grid = [
        [1, 1, 1],
        [1, 1, 1],
        [1, 1, 1]
    ]
    astar = AStarGrid(grid)
    path = astar.find_path((0, 0), (2, 2))
    assert is_valid_path(grid, path)
    assert calculate_path_cost(grid, path) == 5


def test_path_around_obstacles():
    grid = [
        [1, 1, 1],
        [1, 0, 1],
        [1, 1, 1]
    ]
    astar = AStarGrid(grid)
    path = astar.find_path((0, 0), (2, 2))
    assert is_valid_path(grid, path)
    assert len(path) == 5


def test_weighted_grid():
    grid = [
        [1, 10, 1],
        [1, 1, 1],
        [1, 10, 1]
    ]
    astar = AStarGrid(grid)
    path = astar.find_path((0, 0), (2, 2))
    assert is_valid_path(grid, path)
    # Should prefer middle row to avoid high-cost cells
    assert calculate_path_cost(grid, path) == 5


def test_no_path_exists():
    grid = [
        [1, 1],
        [0, 0]
    ]
    astar = AStarGrid(grid)
    path = astar.find_path((0, 0), (1, 1))
    assert path is None


def test_start_equals_end():
    grid = [[1, 1], [1, 1]]
    astar = AStarGrid(grid)
    path = astar.find_path((0, 0), (0, 0))
    assert path == [(0, 0)]


def test_invalid_coordinates():
    grid = [[1, 1], [1, 1]]
    astar = AStarGrid(grid)

    with pytest.raises(ValueError):
        astar.find_path((-1, 0), (0, 0))

    with pytest.raises(ValueError):
        astar.find_path((0, 2), (0, 0))


def test_start_or_end_is_wall():
    grid = [
        [1, 1],
        [0, 1]
    ]
    astar = AStarGrid(grid)

    assert astar.find_path((0, 0), (1, 0)) is None
    assert astar.find_path((1, 0), (0, 0)) is None


def test_optimality_weighted():
    grid = [
        [1, 5, 1],
        [1, 1, 1],
        [1, 5, 1]
    ]
    astar = AStarGrid(grid)
    path = astar.find_path((0, 0), (2, 2))

    assert is_valid_path(grid, path)
    # Optimal path avoids high-cost cells
    assert calculate_path_cost(grid, path) == 5


if __name__ == "__main__":
    pytest.main([__file__, "-v"])
